<?php
 namespace WPAICG\Core; use WP_Error; use WPAICG\AIPKit_Providers; use WPAICG\Core\Providers\ProviderStrategyFactory; if (!defined('ABSPATH')) { exit; } class AIPKit_Models_API { public static function get_models($provider, $api_params = []) { $strategy = ProviderStrategyFactory::get_strategy($provider); if (is_wp_error($strategy)) { return $strategy; } return $strategy->get_models($api_params); } public static function group_openai_models($models) { $groups = [ 'gpt-5 models' => [], 'gpt-4 models' => [], 'gpt-3.5 models' => [], 'fine-tuned models' => [], 'o1 models' => [], 'o3 models' => [], 'o4 models' => [], 'others' => [], ]; if (empty($models) || !is_array($models)) { return $groups; } foreach ($models as $model) { $id = $model['id'] ?? ''; if (empty($id)) continue; $idLower = strtolower($id); if (strpos($id, 'ft:') === 0 || strpos($id, ':ft-') !== false) { $groups['fine-tuned models'][] = $model; } elseif (strpos($idLower, 'gpt-5') !== false) { $groups['gpt-5 models'][] = $model; } elseif (strpos($idLower, 'gpt-4') !== false) { $groups['gpt-4 models'][] = $model; } elseif (strpos($idLower, 'gpt-3.5') !== false) { $groups['gpt-3.5 models'][] = $model; } elseif (strpos($idLower, 'o1') !== false) { $groups['o1 models'][] = $model; } elseif (strpos($idLower, 'o3') !== false) { $groups['o3 models'][] = $model; } elseif (strpos($idLower, 'o4') !== false) { $groups['o4 models'][] = $model; } else { $groups['others'][] = $model; } } $groups = array_filter($groups); foreach ($groups as &$items) { usort($items, fn($a, $b) => strcmp($b['id'], $a['id'])); } unset($items); $ordered_groups = []; $order = ['o1 models', 'o3 models', 'o4 models', 'gpt-3.5 models', 'gpt-4 models', 'gpt-5 models', 'fine-tuned models', 'others']; foreach($order as $key) { if (isset($groups[$key])) { $ordered_groups[$key] = $groups[$key]; } } return $ordered_groups; } }